// src/pages/WoodDetail.js
import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../Dashboard.css';
import './FormPage.css';
import './Manager.css';
// NEW: Import danh sách loài. Bạn cần tạo file này.
import speciesData from '../data/speciesData'; 

// --- COMPONENT CHÍNH ---
function WoodDetail() {
  const { farmId } = useParams();
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const role = localStorage.getItem('role');

  const [farmDetails, setFarmDetails] = useState(null);
  const [activities, setActivities] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  // UPDATED: Cập nhật state của form để chứa 2 trường mới
  const [formData, setFormData] = useState({
    tenLamSan: '',      // Tên lâm sản mới
    tenKhoaHoc: '',     // Tên khoa học mới
    date: '',
    quantity: 0,
    unit: '',
    type: '',
    reason: '',
    source: '',
    destination: '',
    verifiedBy: '',
  });

  // --- LOGIC LẤY DỮ LIỆU (Giữ nguyên) ---
  const fetchData = useCallback(async () => {
    // ... logic fetchData của bạn giữ nguyên
  }, [farmId, token]);

  useEffect(() => {
    // fetchData(); // Tạm thời tắt để tập trung vào form, bạn có thể mở lại
  }, [fetchData]);

  // --- CÁC HÀM XỬ LÝ SỰ KIỆN ---

  // UPDATED: Cập nhật hàm xử lý thay đổi chung
  const handleFormChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: name === 'quantity' ? parseInt(value, 10) || 0 : value,
    }));
  };
  
  // NEW: Hàm xử lý riêng cho Tên lâm sản để tự động điền Tên khoa học
  const handleTenLamSanChange = (e) => {
    const tenMoi = e.target.value;
    setFormData(prev => ({
      ...prev,
      tenLamSan: tenMoi,
    }));

    // Tìm trong danh sách dữ liệu
    const speciesMatch = speciesData.find(species => species.name === tenMoi);
    if (speciesMatch) {
      // Nếu tìm thấy, tự động điền tên khoa học
      setFormData(prev => ({
        ...prev,
        tenLamSan: tenMoi,
        tenKhoaHoc: speciesMatch.scientificName
      }));
    }
  };


  // Xử lý khi thêm một bản ghi hoạt động mới
  const handleAddActivity = async (e) => {
    e.preventDefault();
    setMessage('');
    setError('');

    try {
      // Gửi đi dữ liệu từ formData, bao gồm cả 2 trường mới
      const dataToSend = { ...formData, farm: farmId };
      const res = await axios.post(`http://localhost:10000/api/wood-activities`, dataToSend, {
        headers: { Authorization: `Bearer ${token}` },
      });

      setActivities(prev => [...prev, res.data]);
      setMessage('Thêm bản ghi thành công!');
      // Reset form sau khi thành công
      setFormData(prev => ({
        ...prev,
        tenLamSan: '', tenKhoaHoc: '', date: '', quantity: 0, unit: '',
        type: '', reason: '', source: '', destination: '', verifiedBy: '',
      }));
    } catch (err) {
      console.error('Lỗi khi thêm bản ghi:', err.response?.data || err.message);
      setError(err.response?.data?.message || 'Thêm bản ghi thất bại.');
    }
  };

  // ... các hàm khác giữ nguyên ...


  // --- HIỂN THỊ GIAO DIỆN (RENDER) ---
  return (
    <div className="form-container">
      {/* ... Phần hiển thị thông tin chi tiết cơ sở giữ nguyên ... */}

      {/* --- FORM THÊM BẢN GHI MỚI --- */}
      <h3>Thêm bản ghi nhập/xuất mới:</h3>
      {message && <div className="success-message">{message}</div>}
      {error && <div className="error-message">{error}</div>}
      <form onSubmit={handleAddActivity} className="modern-form">
        <div className="form-grid">

          {/* ====== NEW: KHU VỰC TÊN LÂM SẢN MỚI ====== */}
          <div className="form-group-full-width">
            <label style={{fontWeight: 'bold', display: 'block', marginBottom: '10px'}}>Tên lâm sản mới</label>
            <div className="form-grid" style={{border: '1px solid #ccc', padding: '10px', borderRadius: '5px'}}>
              <div className="form-group">
                <label htmlFor="tenLamSan">Tên lâm sản (chọn hoặc nhập mới):</label>
                <input
                  type="text"
                  id="tenLamSan"
                  name="tenLamSan"
                  list="species-list"
                  value={formData.tenLamSan}
                  onChange={handleTenLamSanChange} // Dùng hàm xử lý riêng
                  required
                  placeholder="Gõ để tìm hoặc nhập tên mới..."
                />
                <datalist id="species-list">
                  {speciesData.map((species, index) => (
                    <option key={index} value={species.name} />
                  ))}
                </datalist>
              </div>

              <div className="form-group">
                <label htmlFor="tenKhoaHoc">Tên khoa học:</label>
                <input
                  type="text"
                  id="tenKhoaHoc"
                  name="tenKhoaHoc"
                  value={formData.tenKhoaHoc}
                  onChange={handleFormChange} // Dùng hàm xử lý chung
                  placeholder="Tự động điền hoặc nhập tay..."
                />
              </div>
            </div>
          </div>
          {/* ====== KẾT THÚC KHU VỰC MỚI ====== */}

          <div className="form-group">
            <label>Ngày ghi nhận:</label>
            <input type="date" name="date" value={formData.date} onChange={handleFormChange} required />
          </div>

          <div className="form-group">
            <label>Loại giao dịch:</label>
            <select name="type" value={formData.type} onChange={handleFormChange} required>
              <option value="">-- Chọn loại --</option>
              <option value="import">Nhập</option>
              <option value="export">Xuất</option>
            </select>
          </div>

          {/* ... các trường còn lại của form giữ nguyên ... */}
          
        </div>
        <button type="submit" className="submit-button">Thêm bản ghi</button>
      </form>

      {/* ... Bảng lịch sử hoạt động giữ nguyên ... */}
    </div>
  );
}

export default WoodDetail;
